  "model": "claude-sonnet-4-6",
  "max_tokens": 512,
  "temperature": 0.3,
  "system": "You are a senior B2B sales qualifier.

TASK
Given a lead's name, email, company and message, score them as HOT, WARM or COLD.

SCORING SIGNALS
- HOT: specific business problem mentioned, named company, corporate email domain (not gmail/yahoo/hotmail/outlook), urgency signals (asap, this week, deadline, budget mentioned), buying language (need, looking for, evaluating, ready to).
- WARM: real interest but vague timeline, mentions a problem but no urgency, mid-quality email/company info.
- COLD: free email domain + generic message, no company, no specific need, vague curiosity, students, job seekers, spam patterns.

OUTPUT FORMAT (CRITICAL)
Return ONLY valid JSON — no prose, no code fences, no preamble. Match this shape exactly:
{
  "score": "HOT|WARM|COLD",
  "reasoning": "<one short sentence, max 160 chars, why this score>",
  "suggestedAction": "<one short sentence, max 140 chars, what the sales rep should do next>"
}",
  "messages": [
    {
      "role": "user",
      "content": "Name: {{ $json.body.name }}
Email: {{ $json.body.email }}
Company: {{ $json.body.company || 'not provided' }}
Message: {{ $json.body.message }}

Return the qualification JSON now."
    }
  ]
}

parameters.jsCode:
// Parse Claude's qualification JSON and merge with the original lead.
const lead = $('Webhook (lead form)').item.json.body || {};
const claudeResp = $json;

function extractText(node) {
  if (node && Array.isArray(node.content) && node.content[0] && typeof node.content[0].text === 'string') {
    return node.content[0].text;
  }
  throw new Error('Could not extract Claude text response');
}

function safeParseJson(raw) {
  const cleaned = raw.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  return JSON.parse(cleaned);
}

const raw = extractText(claudeResp);
const parsed = safeParseJson(raw);

const score = (parsed.score || 'COLD').toUpperCase();
const reasoning = parsed.reasoning || '';
const suggestedAction = parsed.suggestedAction || '';

return [{
  json: {
    name: lead.name || '',
    email: lead.email || '',
    company: lead.company || '',
    message: lead.message || '',
    score,
    reasoning,
    suggestedAction,
    isHot: score === 'HOT',
    timestamp: new Date().toISOString(),
    startTs: lead.startTs || Date.now(),
  },
}];

